import{c as n,Q as a,j as e,m as l}from"./chunks/framework.rlpw0eGz.js";const b=JSON.parse('{"title":"node npmrc 设置镜像源","description":"node npmrc 设置镜像源 —— 2023-07-28","frontmatter":{"title":"node npmrc 设置镜像源","description":"node npmrc 设置镜像源 —— 2023-07-28","date":"2023-07-28T00:00:00.000Z"},"headers":[],"relativePath":"notes/node npmrc 设置镜像源.md","filePath":"notes/node npmrc 设置镜像源.md","lastUpdated":null}'),p={name:"notes/node npmrc 设置镜像源.md"};function r(o,s,t,c,i,m){return a(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="node-npmrc-设置镜像源" tabindex="-1">node npmrc 设置镜像源 <a class="header-anchor" href="#node-npmrc-设置镜像源" aria-label="Permalink to &quot;node  npmrc  设置镜像源&quot;">​</a></h1><p class="note-date">2023-07-28</p><p><a href="https://zhuanlan.zhihu.com/p/614932837" target="_blank" rel="noreferrer">npm 的配置文件 .npmrc</a></p><h2 id="优先级" tabindex="-1">优先级 <a class="header-anchor" href="#优先级" aria-label="Permalink to &quot;优先级&quot;">​</a></h2><p>项目根目录的 <code>.npmrc</code> 的配置，优先级最高，且随着项目一起，可以免去因不同开发者的电脑的环境配置不同而导致的依赖下载异常的问题；实际开发中也推荐在根目录下配置一份，可以给每个项目配置不同的镜像，项目之间的配置互不影响。</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="color:#7F848E;font-style:italic;"># 配置 npm 的默认镜像源为淘宝镜像源</span></span>
<span class="line"><span style="color:#61AFEF;">registry</span><span style="color:#98C379;"> =</span><span style="color:#98C379;"> &quot;https://registry.npm.taobao.org&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 配置此项目的局部镜像源之 electron</span></span>
<span class="line"><span style="color:#61AFEF;">electron_mirror</span><span style="color:#98C379;"> =</span><span style="color:#98C379;"> &quot;https://npm.taobao.org/mirrors/electron/&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 配置此项目的局部镜像源之 sass</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># node-sass 现在很少有项目用了，主要用来兼容一些老旧项目</span></span>
<span class="line"><span style="color:#E06C75;">sass_binary_site</span><span style="color:#56B6C2;">=</span><span style="color:#98C379;"> &quot;https://npm.taobao.org/mirrors/node-sass/&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># node 版本与 package.json 配置不同的时候，中断命令执行</span></span>
<span class="line"><span style="color:#61AFEF;">engine-strict</span><span style="color:#98C379;"> =</span><span style="color:#D19A66;"> true</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h2 id="常用镜像源" tabindex="-1">常用镜像源 <a class="header-anchor" href="#常用镜像源" aria-label="Permalink to &quot;常用镜像源&quot;">​</a></h2><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code" tabindex="0"><code><span class="line"><span style="color:#7F848E;font-style:italic;"># 淘宝镜像源</span></span>
<span class="line"><span style="color:#61AFEF;">https://registry.npmmirror.com</span></span>
<span class="line"><span style="color:#61AFEF;">https://registry.npm.taobao.org</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 腾讯云镜像源</span></span>
<span class="line"><span style="color:#61AFEF;">http://mirrors.cloud.tencent.com/npm/</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 华为云镜像源</span></span>
<span class="line"><span style="color:#61AFEF;">https://mirrors.huaweicloud.com/repository/npm/</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 官方默认全局镜像</span></span>
<span class="line"><span style="color:#61AFEF;">https://registry.npmjs.org</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>yarn 会读取.npmrc 的配置文件，所以不必为 yarn 再设置一次</li><li>删除 <code>.npmrc</code> 文件，即可恢复默认配置</li><li>项目根目录命令行 <code>npm config get registry</code> 查看是否设置成功</li></ul>`,10)])])}const u=n(p,[["render",r]]);export{b as __pageData,u as default};
